import{_ as n,c as t,o as i,ag as r}from"./chunks/framework.091VdYs-.js";const g=JSON.parse('{"title":"Shopitech – Web-Projekte","description":"","frontmatter":{"aside":true},"headers":[],"relativePath":"projekte/shopitech.md","filePath":"projekte/shopitech.md"}'),s={name:"projekte/shopitech.md"};function a(h,e,d,o,l,u){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="shopitech-–-web-projekte" tabindex="-1">Shopitech – Web-Projekte <a class="header-anchor" href="#shopitech-–-web-projekte" aria-label="Permalink to &quot;Shopitech – Web-Projekte&quot;">​</a></h1><p><strong>Kundenprojekte · Verschiedene Technologien · <a href="https://www.shopitech.de" target="_blank" rel="noreferrer">www.shopitech.de</a></strong></p><p>Shopitech ist der Name, unter dem ich einige Web-Projekte für Kunden gebaut habe – ausgewählte Einzelprojekte für Unternehmen und Personen aus meinem Umfeld. Kein großes Agenturgeschäft, sondern gezielte Zusammenarbeit mit wenigen Kunden, bei denen ich den direkten Kontakt und die vollständige Kontrolle über Technologieentscheidungen schätze.</p><h2 id="die-projekte" tabindex="-1">Die Projekte <a class="header-anchor" href="#die-projekte" aria-label="Permalink to &quot;Die Projekte&quot;">​</a></h2><p><strong><a href="https://www.cw-baden.de" target="_blank" rel="noreferrer">cw-baden.de</a></strong> ist die Website eines Handwerker-Service-Unternehmens in Baden-Baden. Der Auftrag war ein vollständiges Rebranding des bestehenden Auftritts kombiniert mit einem WordPress-Update – veraltetes Theme, veraltete Plugins, unstrukturierter Inhalt. Das Ergebnis: ein sauberer, schneller Auftritt, der für lokale Suche optimiert ist. Ein handwerklicher Betrieb gewinnt seine Kunden über Google Maps und lokale Suchanfragen, nicht über Social Media – das bestimmt die Prioritäten beim Aufbau der Seite.</p><p><strong><a href="https://www.mango-thai.de" target="_blank" rel="noreferrer">mango-thai.de</a></strong> ist die Website eines Thai-Restaurants. Hier stand die visuelle Darstellung im Vordergrund: Speisekarte, Atmosphäre, Reservierungsmöglichkeit. Technisch umgesetzt mit Next.js und React, deployed über Vercel. Restaurants leben von der Erwartung, die sie vor dem ersten Besuch erzeugen – eine Webseite muss das leisten was ein Schaufenster in der Fußgängerzone früher geleistet hat.</p><p><strong>dein-notruf.de</strong> ist ein Hausnotruf-Service, den ich zusammen mit einer Freundin aufbaue. Aktuell noch in der frühen Phase – die Website steht, die Grundstruktur ist gelegt, aber das Geschäftsmodell wird noch ausgearbeitet.</p><p><strong>tinybill.de</strong> – als Teil des Shopitech-Portfolios gelistet, aber ausführlicher auf der <a href="/projekte/tinybill.html">eigenen Seite</a> beschrieben.</p><h2 id="technische-entscheidungen" tabindex="-1">Technische Entscheidungen <a class="header-anchor" href="#technische-entscheidungen" aria-label="Permalink to &quot;Technische Entscheidungen&quot;">​</a></h2><p>Die Technologieauswahl war bei jedem Projekt verschieden – und das bewusst. Ein Handwerker-Service und ein Restaurant haben andere Anforderungen als eine Webanwendung. Wer überall denselben Stack einsetzt, optimiert für das Werkzeug, nicht für das Problem.</p><p>Für die statischen Seiten habe ich anfangs mit Next.js gearbeitet. Next.js ist ein hervorragendes Framework für Anwendungen, die tatsächlich Anwendungscharakter haben – dynamische Daten, Authentifizierung, komplexe Interaktionen. Für eine einfache Präsenzseite ist es schnell mehr Aufwand als nötig: Build-Pipeline aufsetzen, Deployment konfigurieren, Dependency-Management. Das alles funktioniert, aber es ist Overhead für ein Problem, das keinen Overhead braucht.</p><p>Deshalb habe ich die Shopitech-Website selbst vor kurzem von Next.js auf Framer migriert. Framer ist ein Design- und Publishing-Tool, das Seiten direkt aus einem visuellen Editor heraus erstellt und deployt. Für eine Unternehmensseite, die primär auf visuellen Eindruck und schnelle Aktualisierbarkeit ausgelegt ist, ist das die ehrlichere Wahl. Ich kann Änderungen in Minuten einspielen, ohne eine Codezeile anzufassen. Kein Build, kein Deployment, kein Warten.</p><p>Das klingt wie ein Schritt zurück für jemanden der hauptberuflich Softwareentwickler ist. Es ist das Gegenteil. Die Fähigkeit zu erkennen, wann ein Werkzeug das richtige ist – auch wenn es kein Code-Werkzeug ist – ist ein Zeichen von Reife. Der beste Code ist der, den man nicht schreiben musste.</p><h2 id="was-kundenprojekte-lehren" tabindex="-1">Was Kundenprojekte lehren <a class="header-anchor" href="#was-kundenprojekte-lehren" aria-label="Permalink to &quot;Was Kundenprojekte lehren&quot;">​</a></h2><p>Wer Software für Kunden baut, die selbst keine Entwickler sind, lernt andere Dinge als wer im Team für interne Systeme entwickelt. Kundenkommunikation ist eine eigene Kompetenz: Anforderungen heraushören, die nicht explizit genannt werden. Erwartungen managen, ohne zu versprechen was nicht machbar ist. Erklären warum etwas so gelöst wird wie es gelöst wird, ohne dabei technisch zu werden.</p><p>Ich habe durch diese Projekte gelernt, was &quot;fertig&quot; wirklich bedeutet. Im Unternehmenskontext gibt es immer die nächste Iteration, den nächsten Sprint, das nächste Release. Bei einem Kundenprojekt gibt es irgendwann eine Website, die live ist und läuft. Dieses Gefühl – und die Verantwortung die damit verbunden ist – schärft die Perspektive auf das was wirklich wichtig ist.</p><hr><p><a href="https://www.shopitech.de" class="cv-download-link" target="_blank" rel="noreferrer">www.shopitech.de</a></p>',18)])])}const p=n(s,[["render",a]]);export{g as __pageData,p as default};
